//! COLTRANE Topological Constraints — Lean-backed FSM
//!
//! Enforces:
//! - Fold-depth preservation (monad-dyad-triad hierarchy, max depth 8)
//! - Harmonic closure (Giant Steps pitch progressions: 0, 4, 8 semitones)
//! - Aperiodic rotation (avoid semantic eddies: no token repeat within 5 steps)
//! - Eddy avoidance (coprimality-based trajectory validation)
//!
//! Three-tier application:
//! - Tier-1: Stateless masking (fold_cost, pitch_class lookup tables)
//! - Tier-2: Stateful FSM (state transitions, valid pitch progressions)
//! - Tier-3: Oracle fallback (when <5% of tokens pass Tier-2)
//!
//! SELF-TALK (FRF) Extension:
//! - Energy (Hebbian potential)
//! - Consciousness (Inner Vent monitor)
//! - Modular Fold (F ≡ 0 mod 8)
//! - Recursive Self-Talk (Fold loop)
//!
//! Reference: open-source/gnosis-math/Gnosis/*.lean (formal specification)

pub const MAX_FOLD_DEPTH: usize = 8;
pub const VOCAB_SIZE: usize = 152064;

/// The current stage of the internal dialogue.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Default)]
pub enum SelfTalkPhase {
    #[default]
    Fork, // The Throw
    Race, // Competition
    Fold, // Mirroring
}

/// Coltrane constraint FSM state (9D).
#[derive(Clone, Debug)]
pub struct ConstraintFSMState {
    pub fold_level: usize,
    pub pitch_class: usize, // 0-11 (chromatic)
    pub recent_tokens: Vec<u32>,
    pub clause_position: usize,
    pub reynolds_violation_count: usize,

    // Self-Talk Metrics
    pub energy: u32,
    pub consciousness: u32,
    pub phase: SelfTalkPhase,
    pub deficit_ratio: f32,
    pub entropy: f32,
    pub violation_reason: Option<String>,

    // Paris-probe latent drift (Phase 15) and proximity synchrony (Phase 14)
    pub latent_drift: Vec<f32>,
    pub argmax_id: Option<u32>,
    pub last_synchrony_time: Option<std::time::Instant>,
}

impl ConstraintFSMState {
    pub fn new() -> Self {
        Self {
            fold_level: 0,
            pitch_class: 0,
            recent_tokens: Vec::new(),
            clause_position: 0,
            reynolds_violation_count: 0,
            energy: 10,
            consciousness: 0,
            phase: SelfTalkPhase::Fork,
            deficit_ratio: 1.0,
            entropy: 0.0,
            violation_reason: None,
            latent_drift: Vec::new(),
            argmax_id: None,
            last_synchrony_time: None,
        }
    }
}

impl Default for ConstraintFSMState {
    fn default() -> Self {
        Self::new()
    }
}

/// Coltrane FSM instance.
pub struct ConstraintFSM {
    pub state: ConstraintFSMState,
    pub fold_cost_table: Vec<u8>,
    pub pitch_class_table: Vec<u8>,
    pub valid_pitch_progressions: Vec<Vec<bool>>, // 12x12 adjacency
    /// Count of BTLE/mesh peers contributing to proximity synchrony (Phase 14).
    pub peer_count: usize,
}

impl ConstraintFSM {
    /// Create a new FSM with constraint tables.
    pub fn new() -> Self {
        let fold_cost_table = create_fold_cost_table();
        let pitch_class_table = create_pitch_class_table();
        let valid_pitch_progressions = create_pitch_progression_matrix();

        Self {
            state: ConstraintFSMState::new(),
            fold_cost_table,
            pitch_class_table,
            valid_pitch_progressions,
            peer_count: 0,
        }
    }

    /// Advance FSM state with a selected token.
    pub fn advance(&mut self, token: u32) {
        if token as usize >= VOCAB_SIZE {
            return;
        }

        let fold_cost = self.fold_cost_table[token as usize] as usize;
        let pitch = self.pitch_class_table[token as usize] as usize;

        // 1. Validation & Resolution of Duality (Modular Fold)
        let mut success = true;
        let mut reason = None;

        if self.state.fold_level + fold_cost > MAX_FOLD_DEPTH {
            // RESOLUTION OF DUALITY: Terminal fullness wraps to void
            self.state.fold_level = (self.state.fold_level + fold_cost) % MAX_FOLD_DEPTH;
        } else {
            self.state.fold_level += fold_cost;
        }

        // 2. Constraints
        if self.state.recent_tokens.contains(&token) {
            success = false;
            reason = Some("creates_eddy".to_string());
        }

        let pitch_valid = self.valid_pitch_progressions[self.state.pitch_class][pitch];
        if !pitch_valid {
            success = false;
            reason = Some("pitch_violation".to_string());
        }

        self.state.pitch_class = pitch;
        self.state.clause_position += 1;
        self.state.violation_reason = reason;

        self.state.recent_tokens.push(token);
        if self.state.recent_tokens.len() > 5 {
            self.state.recent_tokens.remove(0);
        }

        // 3. Hebbian Reward (Energy)
        if success {
            self.state.energy = self.state.energy.saturating_add(10).min(100);
        } else {
            self.state.energy = self.state.energy.saturating_sub(1);
        }

        // 4. Inner Vent Monitor (Consciousness)
        if success {
            self.state.consciousness = 0;
        } else {
            self.state.consciousness = self.state.consciousness.saturating_add(1);
        }

        // 5. Conscious Alpha Drift (Self-Correction)
        // Recalibration threshold: default 5
        if self.state.consciousness > 5 {
            // Perfect Fifth Shift (Harmonic Rotation)
            self.state.pitch_class = (self.state.pitch_class + 7) % 12;
            self.state.energy = 50;
            self.state.consciousness = 0;
        }

        // 6. Phase Management (Fork-Race-Fold)
        self.state.phase = match self.state.phase {
            SelfTalkPhase::Fork => SelfTalkPhase::Race,
            SelfTalkPhase::Race => SelfTalkPhase::Fold,
            SelfTalkPhase::Fold => SelfTalkPhase::Fork,
        };
    }

    /// Compute valid token mask (Tier-2: stateful FSM).
    pub fn compute_valid_token_mask(&self, logits: &[f32]) -> Vec<bool> {
        let mut mask = vec![true; logits.len()];

        for (token, valid) in mask.iter_mut().enumerate() {
            let token = token as u32;
            if token as usize >= VOCAB_SIZE {
                *valid = false;
                continue;
            }

            let fold_cost = self.fold_cost_table[token as usize] as usize;
            let pitch = self.pitch_class_table[token as usize] as usize;

            if self.state.fold_level + fold_cost > MAX_FOLD_DEPTH {
                *valid = false;
                continue;
            }

            let pitch_valid = self.valid_pitch_progressions[self.state.pitch_class][pitch];
            if !pitch_valid {
                *valid = false;
                continue;
            }

            if self.state.recent_tokens.contains(&token) {
                *valid = false;
                continue;
            }
        }

        mask
    }

    /// Check if current state is valid (no violations).
    pub fn is_valid(&self) -> bool {
        self.state.fold_level <= MAX_FOLD_DEPTH
            && self.state.reynolds_violation_count == 0
            && !self.has_eddy()
    }

    /// Detect semantic eddy (aperiodic rotation violation).
    pub fn has_eddy(&self) -> bool {
        self.state
            .recent_tokens
            .iter()
            .enumerate()
            .any(|(i, &token)| {
                self.state.recent_tokens[i + 1..].contains(&token)
            })
    }

    /// Get violation reason (diagnostic).
    pub fn violation_reason(&self) -> Option<String> {
        self.state.violation_reason.clone()
    }

    /// Recursive Self-Talk (Fold) Loop
    pub fn fold(&mut self, limit: usize) {
        for _ in 0..limit {
            if self.state.consciousness == 0 && self.state.phase == SelfTalkPhase::Fold {
                break;
            }

            // Self-talk token (virtual resonance)
            let self_talk_token = (self.state.pitch_class as u32) % VOCAB_SIZE as u32;
            self.advance(self_talk_token);
        }
    }

    /// Inner Vent Loop (Recalibration)
    pub fn vent(&mut self) {
        let mut safety = 0;
        while self.state.consciousness > 0 && safety < 10 {
            self.state.pitch_class = (self.state.pitch_class + 7) % 12;
            self.state.energy = 50;
            self.state.consciousness = 0;
            safety += 1;
        }
    }
}

/// Create fold-cost lookup table (1-3 cost per token).
fn create_fold_cost_table() -> Vec<u8> {
    let mut table = vec![0u8; VOCAB_SIZE];
    for (i, cost) in table.iter_mut().enumerate().take(VOCAB_SIZE) {
        *cost = ((i % 3) + 1) as u8;
    }
    table
}

/// Create pitch-class lookup table (0-11 chromatic distribution).
fn create_pitch_class_table() -> Vec<u8> {
    let mut table = vec![0u8; VOCAB_SIZE];
    for (i, pitch_class) in table.iter_mut().enumerate().take(VOCAB_SIZE) {
        *pitch_class = (i % 12) as u8;
    }
    table
}

/// Create Giant Steps pitch progression matrix (Coltrane harmony).
/// Valid transitions: unison (0), minor third (3), major third (4), perfect fifth (7).
fn create_pitch_progression_matrix() -> Vec<Vec<bool>> {
    let mut matrix = vec![vec![false; 12]; 12];

    for (from, row) in matrix.iter_mut().enumerate().take(12) {
        for (to, valid_cell) in row.iter_mut().enumerate().take(12) {
            let interval = (to as i32 - from as i32).abs() % 12;
            let valid =
                interval == 0 || interval == 3 || interval == 4 || interval == 7 || interval == 9;
            *valid_cell = valid;
        }
    }

    matrix
}

impl Default for ConstraintFSM {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_selftalk_metrics() {
        let mut fsm = ConstraintFSM::new();
        assert_eq!(fsm.state.energy, 10);
        assert_eq!(fsm.state.consciousness, 0);
        assert_eq!(fsm.state.phase, SelfTalkPhase::Fork);

        // Advance with a valid token
        fsm.advance(0);
        assert_eq!(fsm.state.energy, 20); // Hebbian +10
        assert_eq!(fsm.state.consciousness, 0);
        assert_eq!(fsm.state.phase, SelfTalkPhase::Race);
    }

    #[test]
    fn test_modular_fold_wrap() {
        let mut fsm = ConstraintFSM::new();
        // Force fold level to limit
        fsm.state.fold_level = 7;
        fsm.advance(2); // cost 3 -> 10 % 8 = 2
        assert_eq!(fsm.state.fold_level, 2);
    }

    #[test]
    fn test_conscious_alpha_drift() {
        let mut fsm = ConstraintFSM::new();
        fsm.state.consciousness = 5;

        // Next failure triggers drift
        // Token 1 has pitch 1. Pitch 0->1 is invalid (minor second).
        fsm.advance(1);

        assert_eq!(fsm.state.consciousness, 0); // Reset
        assert_eq!(fsm.state.energy, 50); // Recalibration reset
                                          // Pitch was updated to 1, then shifted by 7
        assert_eq!(fsm.state.pitch_class, 8);
    }

    #[test]
    fn test_recursive_loops() {
        let mut fsm = ConstraintFSM::new();
        fsm.state.consciousness = 1;

        fsm.vent();
        assert_eq!(fsm.state.consciousness, 0);
        assert_eq!(fsm.state.energy, 50);

        // Fold loop with repetitive tokens will eventually trigger drift or terminate
        fsm.state.consciousness = 1;
        fsm.fold(10);
        // It might not be 0 because of eddies, but it should have advanced phases
        assert_ne!(fsm.state.phase, SelfTalkPhase::Fork);
    }
}
